actions.script:
import org.moqui.context.ExecutionContext
import org.moqui.plc4j.Plc4jToolFactory
import org.moqui.plc4j.FieldbusClient
import org.moqui.plc4j.Plc4jUtil

if (!connection) throw new IllegalArgumentException("A connection instance is required for Apache Plc4j to communicate with the device ${request.deviceId}. Device request with name ${request.requestName}, aborted.")

ExecutionContext ec = context.ec
final Plc4jToolFactory tool = ec.getTool(Plc4jToolFactory.TOOL_NAME, Plc4jToolFactory.class)

String  connectionString = Plc4jUtil.buildConnectionString(connection)
ec.logger.info("Connecting to device with ID ${request.deviceId} with connection string ${connectionString}.")
// build client via the tool factory
try (FieldbusClient client =
        (userAccount?.username && userAccount?.currentPassword)
        ? tool.getClient(connectionString, userAccount.username, userAccount.currentPassword)
        : tool.getClient(connectionString)) {

    // dispatch request
    if ("DrtRead" == request.requestTypeEnumId) {
        client.read(request, bulkRequestItemList, requestItemList)
    } else if ("DrtWrite" == request.requestTypeEnumId) {
        client.write(request, bulkRequestItemList, requestItemList)
    } else if ("DrtEvent" == request.requestTypeEnumId || "DrtStateChange" == request.requestTypeEnumId
            || "DrtCyclic" == request.requestTypeEnumId) {
        client.subscribe(request, bulkRequestItemList, requestItemList)
    } else if ("DrtUnsubscribe" == request.requestTypeEnumId) {
        client.unsubscribe(request, requestItemList)
    } else {
        throw new IllegalArgumentException("Unsupported device request type ${request.requestTypeEnumId}. Could not send the device request with name ${request.requestName}.")
    }
}
